    },
    {
      "input": {
        "namespace": "test",
        "annotations": {
          "vault.hashicorp.com/agent-init-first": "true",
          "vault.hashicorp.com/role": "demo",
          "vault.hashicorp.com/agent-inject": "true"
        },
        "op": "mutate"
      },
      "expected_output": "{\"allowed\":true,\"patches\":[{\"op\":\"add\",\"path\":\"/spec/volumes\"},{\"op\":\"add\",\"path\":\"/spec/volumes/-\"},{\"op\":\"add\",\"path\":\"/spec/volumes\"},{\"op\":\"add\",\"path\":\"/spec/containers/0/volumeMounts/-\"},{\"op\":\"remove\",\"path\":\"/spec/initContainers\"},{\"op\":\"add\",\"path\":\"/spec/initContainers\"},{\"op\":\"add\",\"path\":\"/spec/initContainers/-\"},{\"op\":\"add\",\"path\":\"/spec/initContainers/1/volumeMounts/-\"},{\"op\":\"add\",\"path\":\"/spec/containers/-\"},{\"op\":\"add\",\"path\":\"/metadata/annotations/vault.hashicorp.com~1agent-inject-status\"}],\"status\":\"ok\"}\n"
